+fn class_vis_char(vis: fm_core::ClassVisibility) -> char {
+    match vis {
+        fm_core::ClassVisibility::Public => '+',
+        fm_core::ClassVisibility::Private => '-',
+        fm_core::ClassVisibility::Protected => '#',
+        fm_core::ClassVisibility::Package => '~',
+    }
+}
